package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// Configuration constants for security limits
const (
	maxResponseBodySize = 10 * 1024 * 1024 // 10MB max response size
	maxRedirects        = 5
	requestTimeout      = 10 * time.Second
)

// isPrivateIP checks if an IP address is private, loopback, or internal
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Check for loopback, link-local, and other special addresses
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for private IP ranges (RFC 1918 and others)
	privateCIDRs := []string{
		"10.0.0.0/8",         // Private network
		"172.16.0.0/12",      // Private network
		"192.168.0.0/16",     // Private network
		"127.0.0.0/8",        // Loopback
		"169.254.0.0/16",     // Link-local (AWS metadata endpoint uses this)
		"0.0.0.0/8",          // Current network
		"100.64.0.0/10",      // Carrier-grade NAT
		"192.0.0.0/24",       // IETF Protocol Assignments
		"192.0.2.0/24",       // TEST-NET-1
		"198.51.100.0/24",    // TEST-NET-2
		"203.0.113.0/24",     // TEST-NET-3
		"198.18.0.0/15",      // Network benchmark tests
		"224.0.0.0/4",        // Multicast
		"240.0.0.0/4",        // Reserved
		"::1/128",            // IPv6 loopback
		"fc00::/7",           // IPv6 unique local
		"fe80::/10",          // IPv6 link-local
		"::ffff:0:0/96",      // IPv4-mapped IPv6
	}

	for _, cidr := range privateCIDRs {
		_, block, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if block.Contains(ip) {
			return true
		}
	}

	return false
}

// validateURLHostname validates that the URL doesn't point to internal resources
func validateURLHostname(parsedURL *url.URL) error {
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid hostname")
	}

	// Check if hostname is an IP address directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private/internal IP addresses is not allowed")
		}
		return nil
	}

	// Resolve DNS and check all resolved IPs
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("hostname resolves to private/internal IP address")
		}
	}

	return nil
}

// validateURL performs comprehensive URL validation for SSRF prevention
func validateURL(targetURL string) (*url.URL, error) {
	// Parse URL
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("URL must use http or https scheme")
	}

	// Validate hostname doesn't point to internal resources
	if err := validateURLHostname(parsedURL); err != nil {
		return nil, err
	}

	return parsedURL, nil
}

// safeDial creates a custom dial function that validates IP addresses at connection time
// This prevents DNS rebinding attacks
func safeDial(addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address format: %v", err)
	}

	// Check if host is an IP address
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private/internal IP addresses is blocked")
		}
	} else {
		// Resolve hostname and validate all IPs
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, fmt.Errorf("failed to resolve hostname: %v", err)
		}

		for _, ip := range ips {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("hostname resolves to private/internal IP address")
			}
		}
	}

	// Use default dialer for actual connection
	dialer := &fasthttp.TCPDialer{
		Concurrency: 1000,
	}
	return dialer.Dial(addr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse request body
	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL for SSRF prevention
	parsedURL, err := validateURL(targetURL)
	if err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Create client with custom dial function and timeouts
	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         requestTimeout,
		WriteTimeout:        requestTimeout,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	// Prepare request
	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Handle redirects manually to validate each redirect target
	redirectCount := 0
	currentURL := parsedURL

	for {
		err := client.Do(freq, res)
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		// Check if it's a redirect
		statusCode := res.StatusCode()
		if statusCode < 300 || statusCode >= 400 {
			break
		}

		redirectCount++
		if redirectCount > maxRedirects {
			ctx.Error("Too many redirects", fasthttp.StatusBadGateway)
			return
		}

		// Get redirect location
		location := res.Header.Peek("Location")
		if len(location) == 0 {
			ctx.Error("Redirect without location header", fasthttp.StatusBadGateway)
			return
		}

		// Parse redirect URL (handle relative URLs)
		redirectURL, err := currentURL.Parse(string(location))
		if err != nil {
			ctx.Error("Invalid redirect URL", fasthttp.StatusBadGateway)
			return
		}

		// Validate redirect URL for SSRF
		if err := validateURLHostname(redirectURL); err != nil {
			ctx.Error(fmt.Sprintf("Redirect blocked: %v", err), fasthttp.StatusBadGateway)
			return
		}

		// Prepare for next request
		freq.SetRequestURI(redirectURL.String())
		currentURL = redirectURL
		fasthttp.ReleaseResponse(res)
		res = fasthttp.AcquireResponse()
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Limit response body size to prevent memory exhaustion
	if len(bodyBytes) > maxResponseBodySize {
		bodyBytes = bodyBytes[:maxResponseBodySize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	return "dummy title", "dummy description", nil
}

