package main

import (
	"encoding/json"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type Request struct {
	URL string `json:"url"`
}

type Response struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial:         fasthttp.DialDualStack,
	ReadTimeout:  3 * time.Second,
	WriteTimeout: 3 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if string(ctx.Method()) != "POST" {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "Method not allowed"})
		return
	}

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "URL is required"})
		return
	}

	// Create request for fetching the URL
	reqAcquire := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(reqAcquire)
	reqAcquire.SetRequestURI(req.URL)

	respAcquire := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(respAcquire)

	// Fetch the URL using DoRedirects
	maxRedirects := 10
	err := client.DoRedirects(reqAcquire, respAcquire, maxRedirects)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{URL: req.URL, Error: err.Error()})
		return
	}

	// Parse HTML to extract title and meta description
	body := respAcquire.Body()
	title, description := extractMeta(body)

	// Return JSON response
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(Response{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func extractMeta(body []byte) (title string, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var extractText func(*html.Node) string
	extractText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result strings.Builder
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			result.WriteString(extractText(c))
		}
		return result.String()
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = extractText(n)
			} else if n.Data == "meta" && description == "" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

