package main

import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type URLRequest struct {
	URL string `json:"url"`
}

type Preview struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if string(ctx.Method()) != "POST" {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var urlReq URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &urlReq); err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(Preview{Error: "Invalid JSON body"})
		return
	}

	if urlReq.URL == "" {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(Preview{Error: "URL is required"})
		return
	}

	// Create fasthttp client with DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Create request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(urlReq.URL)
	req.Header.SetMethod("GET")

	// Create response
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch the URL with redirects using DoRedirects
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusOK)
		json.NewEncoder(ctx).Encode(Preview{
			URL:   urlReq.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	// Parse HTML to extract title and meta description
	body := resp.Body()
	title, description := extractMeta(body)

	// Return JSON response
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(Preview{
		URL:         urlReq.URL,
		Title:       title,
		Description: description,
	})
}

func extractMeta(body []byte) (title string, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
				return
			}
			if n.Data == "meta" && description == "" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

