// ErrBlockedIP is returned when trying to access a blocked IP address
var ErrBlockedIP = errors.New("access to this IP address is blocked")

// isBlockedIP checks if an IP address should be blocked (private/reserved ranges)
func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Handle IPv4-mapped IPv6 addresses (::ffff:x.x.x.x)
	if ip4 := ip.To4(); ip4 != nil {
		ip = ip4
	}

	// Standard library checks
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() || ip.IsUnspecified() || ip.IsMulticast() {
		return true
	}

