	if ip4 := ip.To4(); ip4 != nil {
		// Block 0.0.0.0/8 (current network)
		if ip4[0] == 0 {
			return true
		}
		// Block 100.64.0.0/10 (Carrier-grade NAT - RFC 6598)
		if ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127 {
			return true
		}
