		for _, ip := range ips {
			if isBlockedIP(ip) {
				return nil, ErrBlockedIP
			}
		}
	}

	// Use standard dialer with timeout
	dialer := &net.Dialer{
		Timeout:   10 * time.Second,
		DualStack: true,
	}
	return dialer.Dial("tcp", net.JoinHostPort(host, port))
