)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse request body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL is required"})
		return
	}

	// Create fasthttp client with 3 second timeout
	client := &fasthttp.Client{
		Dial:        fasthttp.DialDualStack,
		ReadTimeout: 3 * time.Second,
	}

	// Create request
	fastReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(fastReq)
	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod("GET")

	// Create response
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(fastResp)

	// Fetch URL with redirects
	err := client.DoRedirects(fastReq, fastResp, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: err.Error()})
		return
	}

	// Parse HTML
	title, description := extractMeta(fastResp.Body())

	// Return response
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func extractMeta(body []byte) (title, description string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			} else if n.Data == "meta" {
				isDescription := false
				var descContent string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					}
					if attr.Key == "content" {
						descContent = attr.Val
					}
				}
				if isDescription {
					description = strings.TrimSpace(descContent)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

