package main

import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type Request struct {
	URL string `json:"url"`
}

type Response struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if string(ctx.Method()) != "POST" {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(Response{
			Error: "Invalid JSON body",
		})
		return
	}

	if req.URL == "" {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(Response{
			Error: "URL is required",
		})
		return
	}

	reqFast := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(reqFast)
	reqFast.SetRequestURI(req.URL)

	respFast := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(respFast)

	err := client.DoRedirects(reqFast, respFast, 10)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusOK)
		json.NewEncoder(ctx).Encode(Response{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	body := respFast.Body()
	title, description := extractMeta(body)

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(Response{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func extractMeta(body []byte) (title string, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			} else if n.Data == "meta" && description == "" {
				isDescription := false
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						isDescription = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

func requestHandler(ctx *fasthttp.RequestCtx) {
	switch string(ctx.Path()) {
	case "/preview":
		FetchURLPreview(ctx)
	default:
		ctx.Error("Not found", fasthttp.StatusNotFound)
	}
}

func main() {
	fasthttp.ListenAndServe(":8080", requestHandler)
}

