		}
	}

	return false
}

// safeDial wraps the dial function with IP validation to prevent SSRF
func safeDial(addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address format")
	}

	// Block localhost explicitly
	if strings.ToLower(host) == "localhost" {
		return nil, fmt.Errorf("access to localhost is not allowed")
	}

	// Resolve hostname to IP
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve hostname")
	}

	// Check if any resolved IP is private/internal
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to internal networks is not allowed")
		}
	}

	// Use the original dial function
	return fasthttp.DialDualStack(addr)
}

