package main

import (
	"encoding/json"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type Request struct {
	URL string `json:"url"`
}

type Response struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial:        fasthttp.DialDualStack,
	ReadTimeout: 3 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if string(ctx.Method()) != "POST" {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "URL is required"})
		return
	}

	// Create request to fetch the URL
	fasthttpRequest := fasthttp.AcquireRequest()
	fasthttpResponse := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fasthttpRequest)
	defer fasthttp.ReleaseResponse(fasthttpResponse)

	fasthttpRequest.SetRequestURI(req.URL)

	// Use DoRedirects with max 10 redirects
	if err := client.DoRedirects(fasthttpRequest, fasthttpResponse, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{URL: req.URL, Error: err.Error()})
		return
	}

	// Parse HTML
	body := fasthttpResponse.Body()
	title, description := extractTitleAndDescription(body)

	// Return response
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(Response{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(body []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				title = extractText(n)
			} else if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func extractText(n *html.Node) string {
	var text string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if c.Type == html.TextNode {
			text += c.Data
		} else {
			text += extractText(c)
		}
	}
	return text
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

