	defer fasthttp.ReleaseRequest(fastReq)
	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod("GET")
	fastReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	// Create response
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch URL with redirects
	maxRedirects := 10
	if err := client.DoRedirects(fastReq, resp, maxRedirects); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(PreviewResponse{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	// Parse HTML
	body := resp.Body()
	title, description := extractMetadata(body)

	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(PreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func extractMetadata(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				title = extractText(n)
			} else if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func extractText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += extractText(c)
	}
	return result
}

func requestHandler(ctx *fasthttp.RequestCtx) {
	path := string(ctx.Path())
	switch path {
	case "/preview":
		FetchURLPreview(ctx)
	default:
		ctx.Error("Not found", fasthttp.StatusNotFound)
	}
}

func main() {
	fasthttp.ListenAndServe(":8080", requestHandler)
}

