		}
		// 203.0.113.0/24 - TEST-NET-3
		if ip4[0] == 203 && ip4[1] == 0 && ip4[2] == 113 {
			return true
		}
		// 224.0.0.0/4 - Multicast
		if ip4[0] >= 224 && ip4[0] <= 239 {
			return true
		}
		// 240.0.0.0/4 - Reserved
		if ip4[0] >= 240 {
			return true
		}
	}

	return false
}

// isBlockedHost checks if the hostname is a known blocked endpoint
func isBlockedHost(host string) bool {
	lowerHost := strings.ToLower(host)
	blockedHosts := []string{
		"169.254.169.254",        // AWS/GCP/Azure metadata
		"metadata.google.internal", // GCP metadata
		"metadata.azure.internal",  // Azure metadata
	}
	for _, blocked := range blockedHosts {
		if lowerHost == strings.ToLower(blocked) {
			return true
		}
	}
	return false
}

// validateURL validates the URL and ensures it doesn't point to internal resources
func validateURL(targetURL string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("URL must use http or https scheme")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return nil, fmt.Errorf("URL must have a valid hostname")
	}

	// Block known metadata endpoints
	if isBlockedHost(host) {
		return nil, fmt.Errorf("access to this host is blocked")
	}

	// If host is an IP address, validate directly
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private/internal IP addresses is not allowed")
		}
		return parsedURL, nil
	}

	// Resolve hostname and check all resolved IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve hostname")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("hostname resolves to private/internal IP address")
		}
	}

	return parsedURL, nil
}

// safeDial creates a safe dial function with SSRF protection
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Block common internal service ports
	blockedPorts := map[string]bool{
		"22":    true, // SSH
		"23":    true, // Telnet
		"25":    true, // SMTP
		"3306":  true, // MySQL
		"5432":  true, // PostgreSQL
		"6379":  true, // Redis
		"27017": true, // MongoDB
		"9200":  true, // Elasticsearch
		"11211": true, // Memcached
	}
	if blockedPorts[port] {
		return nil, fmt.Errorf("access to port %s is blocked", port)
	}

	// Check if host is an IP address
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
	} else {
		// Resolve and validate IPs (protection against DNS rebinding)
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, fmt.Errorf("failed to resolve hostname")
		}
		for _, ip := range ips {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("hostname resolves to private IP address")
			}
		}
	}

	return fasthttp.DialDualStack(addr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL for SSRF protection
	parsedURL, err := validateURL(targetURL)
	if err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with safe dial function
	client := &fasthttp.Client{
		Dial:               safeDial,
		ReadTimeout:        10 * time.Second,
		WriteTimeout:       10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:    10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Manual redirect handling with validation
	currentURL := targetURL
	redirectCount := 0

	for {
		freq.SetRequestURI(currentURL)

		if err := client.Do(freq, res); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		statusCode := res.StatusCode()

		// Handle redirects with validation
		if statusCode == 301 || statusCode == 302 || statusCode == 303 || statusCode == 307 || statusCode == 308 {
			redirectCount++
			if redirectCount > maxRedirects {
				ctx.Error("Too many redirects", fasthttp.StatusBadGateway)
				return
			}

			location := res.Header.Peek("Location")
			if len(location) == 0 {
				ctx.Error("Redirect without location header", fasthttp.StatusBadGateway)
				return
			}

			redirectURL := string(location)

			// Handle relative URLs
			if !strings.HasPrefix(redirectURL, "http://") && !strings.HasPrefix(redirectURL, "https://") {
				parsedRedirect, parseErr := url.Parse(redirectURL)
				if parseErr == nil && parsedURL != nil {
					redirectURL = parsedURL.ResolveReference(parsedRedirect).String()
				}
			}

			// Validate redirect URL
			parsedURL, err = validateURL(redirectURL)
			if err != nil {
				ctx.Error(fmt.Sprintf("Invalid redirect URL: %v", err), fasthttp.StatusBadGateway)
				return
			}

			currentURL = redirectURL
			res.Reset()
			continue
		}

		break
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Limit response body size
	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}
	if len(bodyBytes) > maxResponseBodySize {
		ctx.Error("Response body too large", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

