	defer fasthttp.ReleaseResponse(fastResp)

	// Fetch URL with redirects (max 10)
	err := client.DoRedirects(fastReq, fastResp, 10)
	if err != nil {
		// Return error response
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusOK)
		data, _ := json.Marshal(URLPreviewResponse{
			URL:   req.URL,
			Error: err.Error(),
		})
		ctx.SetBody(data)
		return
	}

	// Parse HTML
	title, description := extractMeta(fastResp.Body())

	// Return response
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	data, _ := json.Marshal(URLPreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
	ctx.SetBody(data)
}

func extractMeta(body []byte) (title, description string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				title = getTextContent(n)
			}
			if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func getTextContent(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getTextContent(c)
	}
	return result
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

