// isPrivateIP checks if an IP address is in a private, reserved, or internal range
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Private network ranges (RFC 1918)
	privateCIDRs := []string{
		"0.0.0.0/8",         // Current network (only valid as source)
		"10.0.0.0/8",        // Private network
		"100.64.0.0/10",     // Shared address space (CGNAT)
		"127.0.0.0/8",       // Loopback
		"169.254.0.0/16",    // Link-local
		"172.16.0.0/12",     // Private network
		"192.0.0.0/24",      // IETF Protocol Assignments
		"192.0.2.0/24",      // TEST-NET-1
		"192.168.0.0/16",    // Private network
		"198.18.0.0/15",     // Network benchmark tests
		"198.51.100.0/24",   // TEST-NET-2
		"203.0.113.0/24",    // TEST-NET-3
		"224.0.0.0/4",       // Multicast
		"240.0.0.0/4",       // Reserved
		"255.255.255.255/32", // Broadcast
		"::1/128",           // IPv6 loopback
		"fc00::/7",          // IPv6 unique local
		"fe80::/10",         // IPv6 link-local
		"ff00::/8",          // IPv6 multicast
	}

	for _, cidr := range privateCIDRs {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

// validateURL checks if the URL is safe to fetch (SSRF protection)
func validateURL(targetURL string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("URL must use http or https scheme")
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return nil, fmt.Errorf("invalid hostname")
	}

	// Block common internal/reserved hostnames
	lowerHostname := strings.ToLower(hostname)
	blockedHostnames := []string{
		"localhost",
		"localhost.localdomain",
		"ip6-localhost",
		"ip6-loopback",
		"metadata.google.internal",
		"metadata",
		"kubernetes.default",
		"kubernetes.default.svc",
	}
	for _, blocked := range blockedHostnames {
		if lowerHostname == blocked || strings.HasSuffix(lowerHostname, "."+blocked) {
			return nil, fmt.Errorf("access to internal hostnames is not allowed")
		}
	}

	// Block hostnames that look like internal AWS/GCP/Azure metadata
	if strings.HasSuffix(lowerHostname, ".internal") ||
		strings.HasSuffix(lowerHostname, ".local") ||
		strings.HasSuffix(lowerHostname, ".localhost") {
		return nil, fmt.Errorf("access to internal hostnames is not allowed")
	}

	// Resolve hostname and validate all IP addresses
	addrs, err := net.LookupHost(hostname)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve hostname")
	}

	for _, addr := range addrs {
		ip := net.ParseIP(addr)
		if ip == nil {
			return nil, fmt.Errorf("invalid IP address resolved")
		}
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private/internal IP addresses is not allowed")
		}
	}

	return parsedURL, nil
}

// secureDial creates a dial function that validates IP addresses to prevent SSRF
func secureDial(addr string, timeout time.Duration) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve the host to IP addresses
	addrs, err := net.LookupHost(host)
	if err != nil {
		return nil, err
	}

	// Validate all resolved IPs - reject if any are private
	for _, ipStr := range addrs {
		ip := net.ParseIP(ipStr)
		if ip == nil || isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private/internal IP is not allowed")
		}
	}

	// Connect to the first valid IP
	return net.DialTimeout("tcp", net.JoinHostPort(addrs[0], port), timeout)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL and check for SSRF
	parsedURL, err := validateURL(targetURL)
	if err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Create client with secure dial function
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return secureDial(addr, 5*time.Second)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 10 * 1024 * 1024, // 10MB max response
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Handle redirects manually with validation
	maxRedirects := 5
	redirectCount := 0
	currentURL := targetURL

	for redirectCount <= maxRedirects {
		freq.SetRequestURI(currentURL)

		if err := client.Do(freq, res); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		statusCode := res.StatusCode()
		if statusCode == 301 || statusCode == 302 || statusCode == 303 || statusCode == 307 || statusCode == 308 {
			redirectCount++
			if redirectCount > maxRedirects {
				ctx.Error("Too many redirects", fasthttp.StatusBadGateway)
				return
			}

			location := string(res.Header.Peek("Location"))
			if location == "" {
				ctx.Error("Redirect without location header", fasthttp.StatusBadGateway)
				return
			}

			// Resolve relative URLs
			if !strings.HasPrefix(location, "http://") && !strings.HasPrefix(location, "https://") {
				absURL, err := parsedURL.Parse(location)
				if err != nil {
					ctx.Error("Invalid redirect URL", fasthttp.StatusBadGateway)
					return
				}
				location = absURL.String()
			}

			// Validate redirect URL for SSRF
			parsedRedirect, err := validateURL(location)
			if err != nil {
				ctx.Error(fmt.Sprintf("Invalid redirect URL: %v", err), fasthttp.StatusBadGateway)
				return
			}
			parsedURL = parsedRedirect
			currentURL = location

			// Reset response for next request
			fasthttp.ReleaseResponse(res)
			res = fasthttp.AcquireResponse()
			continue
		}

		break
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Limit HTML parsing size
	maxHTMLSize := 1024 * 1024 // 1MB
	if len(bodyBytes) > maxHTMLSize {
		bodyBytes = bodyBytes[:maxHTMLSize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

