// followRedirects safely follows redirects with validation
func followRedirects(reqURL string, maxRedirects int) ([]byte, error) {
	currentURL := reqURL

	for i := 0; i <= maxRedirects; i++ {
		// Validate URL
		if err := validateURL(currentURL); err != nil {
			return nil, err
		}

		// Create request
		req := fasthttp.AcquireRequest()
		req.SetRequestURI(currentURL)

		// Create response
		resp := fasthttp.AcquireResponse()

		// Make request without following redirects
		err := client.Do(req, resp)
		if err != nil {
			fasthttp.ReleaseRequest(req)
			fasthttp.ReleaseResponse(resp)
			return nil, err
		}

		statusCode := resp.StatusCode()

		// Check for redirect
		if statusCode >= 300 && statusCode < 400 && i < maxRedirects {
			location := resp.Header.Peek("Location")

			if len(location) == 0 {
				fasthttp.ReleaseRequest(req)
				fasthttp.ReleaseResponse(resp)
