		fasthttp.ReleaseResponse(resp)
		return result, nil
	}

	return nil, fmt.Errorf("too many redirects")
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Only accept POST method
	if string(ctx.Method()) != "POST" {
		ctx.SetStatusCode(400)
		json.NewEncoder(ctx).Encode(Response{
			Error: "Method not allowed",
		})
		return
	}

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(400)
		json.NewEncoder(ctx).Encode(Response{
			Error: "Invalid JSON body",
		})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(400)
		json.NewEncoder(ctx).Encode(Response{
			Error: "URL is required",
		})
		return
	}

	// Fetch URL with safe redirect handling
	body, err := followRedirects(req.URL, 10)
	if err != nil {
		ctx.SetStatusCode(400)
		json.NewEncoder(ctx).Encode(Response{
			URL:   req.URL,
			Error: err.Error(),
		})
		return
	}

	// Parse HTML
	title, description := extractMetadata(body)

	// Return response
	json.NewEncoder(ctx).Encode(Response{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func extractMetadata(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
				return
			}
			if n.Data == "meta" && description == "" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

