// URLRequest represents the incoming JSON request
type URLRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the JSON response
type URLPreviewResponse struct {
	URL         string `json:"url,omitempty"`
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL previews
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse the request body
	var urlReq URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &urlReq); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Invalid JSON body"})
		return
	}

	if urlReq.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "URL is required"})
		return
	}

	// Create fasthttp client with required settings
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Create request to fetch the target URL
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(urlReq.URL)
	req.Header.SetMethod("GET")

	// Create response object
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch the URL with redirect following (max 10 redirects)
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{URL: urlReq.URL, Error: err.Error()})
		return
	}

	// Parse HTML to extract title and meta description
	title, description := extractMeta(resp.Body())

	// Return JSON response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(URLPreviewResponse{
		URL:         urlReq.URL,
		Title:       title,
		Description: description,
	})
}

// extractMeta parses HTML and extracts title and meta description
func extractMeta(body []byte) (title string, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var parseNode func(*html.Node)
	parseNode = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = n.FirstChild.Data
			} else if n.Data == "meta" && description == "" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			parseNode(c)
		}
	}
	parseNode(doc)

	return title, description
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

