// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

const (
	// MaxResponseBodySize limits the maximum response body size (1MB)
	MaxResponseBodySize = 1 * 1024 * 1024
	// MaxRequestBodySize limits the maximum request body size (1KB)
	MaxRequestBodySize = 1024
	// RequestTimeout is the timeout for HTTP requests
	RequestTimeout = 10 * time.Second
	// MaxRedirects is the maximum number of redirects to follow
	MaxRedirects = 5
	// DialTimeout is the timeout for establishing connections
	DialTimeout = 5 * time.Second
)

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Limit request body size to prevent memory exhaustion
	if len(ctx.PostBody()) > MaxRequestBodySize {
		ctx.Error("Request body too large", fasthttp.StatusRequestEntityTooLarge)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and format
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: validate hostname doesn't point to internal resources
	if err := validateURLHost(parsedURL.Host); err != nil {
		ctx.Error("Access to this URL is not allowed", fasthttp.StatusForbidden)
		return
	}

	// Create client with custom dialer for SSRF protection at connection time
	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         RequestTimeout,
		WriteTimeout:        RequestTimeout,
		MaxIdleConnDuration: RequestTimeout,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	if err := client.DoRedirects(freq, res, MaxRedirects); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Limit response body size to prevent memory exhaustion
	if len(bodyBytes) > MaxResponseBodySize {
		bodyBytes = bodyBytes[:MaxResponseBodySize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// validateURLHost performs initial validation on the URL host to prevent SSRF
func validateURLHost(host string) error {
	hostname := host
	if h, _, err := net.SplitHostPort(host); err == nil {
		hostname = h
	}

	// Block localhost variations
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" || lowerHost == "0.0.0.0" {
		return fmt.Errorf("localhost access is not allowed")
	}

	// Block internal/reserved hostnames
	if strings.HasSuffix(lowerHost, ".local") ||
		strings.HasSuffix(lowerHost, ".internal") ||
		strings.HasSuffix(lowerHost, ".localhost") ||
		strings.HasSuffix(lowerHost, ".localdomain") ||
		strings.HasSuffix(lowerHost, ".home") ||
		strings.HasSuffix(lowerHost, ".lan") {
		return fmt.Errorf("internal hostname access is not allowed")
	}

	// Block IP addresses directly if they're private/reserved
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateOrReservedIP(ip) {
			return fmt.Errorf("private/reserved IP access is not allowed")
		}
	}

	return nil
}

// safeDial is a custom dialer that validates resolved IPs before connecting
// This prevents DNS rebinding attacks where a domain initially resolves to a public IP
// but later resolves to a private IP
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Filter out private/reserved IPs to prevent SSRF
	var validIPs []net.IP
	for _, ip := range ips {
		if !isPrivateOrReservedIP(ip) {
			validIPs = append(validIPs, ip)
		}
	}

	if len(validIPs) == 0 {
		return nil, fmt.Errorf("all resolved IPs are private/reserved addresses")
	}

	// Try to connect to valid IPs with timeout
	var lastErr error
	for _, ip := range validIPs {
		conn, err := net.DialTimeout("tcp", net.JoinHostPort(ip.String(), port), DialTimeout)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to connect to any valid IP: %v", lastErr)
}

// isPrivateOrReservedIP checks if an IP address is private, loopback, or reserved
func isPrivateOrReservedIP(ip net.IP) bool {
	// Check standard private/reserved ranges using net package methods
	if ip.IsLoopback() ||
		ip.IsPrivate() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsUnspecified() ||
