	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if string(ctx.Method()) != "POST" {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "Method not allowed"})
		return
	}

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "URL is required"})
		return
	}

	// Fetch the URL
	reqFast := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(reqFast)
	reqFast.SetRequestURI(req.URL)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Use DoRedirects to follow redirects
	err := client.DoRedirects(reqFast, resp, 10) // 10 max redirects
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{URL: req.URL, Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
		return
	}

	// Parse HTML
	body := resp.Body()
	title, description := extractMeta(body)

	// Return response
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(Response{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

func extractMeta(body []byte) (title string, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var extractText func(*html.Node) string
	extractText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var text string
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			text += extractText(c)
		}
		return text
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
