	"127.0.0.0/8",        // Loopback
	"169.254.0.0/16",     // Link-local
	"172.16.0.0/12",      // Private network (RFC 1918)
	"192.0.0.0/24",       // IETF Protocol Assignments
	"192.0.2.0/24",       // TEST-NET-1
	"192.168.0.0/16",     // Private network (RFC 1918)
	"198.18.0.0/15",      // Network benchmark tests
	"198.51.100.0/24",    // TEST-NET-2
	"203.0.113.0/24",     // TEST-NET-3
	"224.0.0.0/4",        // Multicast
	"240.0.0.0/4",        // Reserved
	"255.255.255.255/32", // Broadcast
	"::1/128",            // Loopback IPv6
	"fc00::/7",           // Unique local IPv6
	"fe80::/10",          // Link-local IPv6
}

// parsedPrivateNetworks is the parsed form of privateCIDRs
var parsedPrivateNetworks []*net.IPNet

func init() {
	for _, cidr := range privateCIDRs {
		_, network, err := net.ParseCIDR(cidr)
		if err == nil {
			parsedPrivateNetworks = append(parsedPrivateNetworks, network)
		}
	}
}

// isPrivateIP checks if an IP address is in a private or reserved range
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Convert to 4-byte representation for IPv4 addresses
	// This handles IPv4-mapped IPv6 addresses
	if ip4 := ip.To4(); ip4 != nil {
		ip = ip4
	}

	// Loopback
	if ip.IsLoopback() {
		return true
	}

	// Link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check against CIDR blocks (includes private networks, multicast, reserved, etc.)
	for _, network := range parsedPrivateNetworks {
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

// safeDial creates a dial function that validates IP addresses before connecting
// This prevents SSRF attacks by blocking connections to private/reserved IP addresses
func safeDial(timeout time.Duration) fasthttp.DialFunc {
	return func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, fmt.Errorf("invalid address format: %w", err)
		}

		var ips []net.IP

		// Check if host is already an IP address
		if ip := net.ParseIP(host); ip != nil {
			ips = []net.IP{ip}
		} else {
			// Resolve hostname to IP addresses
			ips, err = net.LookupIP(host)
			if err != nil {
				return nil, fmt.Errorf("failed to resolve hostname: %w", err)
			}
		}

		if len(ips) == 0 {
			return nil, fmt.Errorf("no IP addresses found for hostname")
		}

		// Validate all resolved IPs are not private/reserved
		for _, resolvedIP := range ips {
			if isPrivateIP(resolvedIP) {
				return nil, fmt.Errorf("connection to private/reserved IP addresses is not allowed")
			}
		}

		// Connect to the first valid IP (prevents DNS rebinding attacks)
		targetAddr := net.JoinHostPort(ips[0].String(), port)

		conn, err := net.DialTimeout("tcp", targetAddr, timeout)
		if err != nil {
			return nil, err
		}

		return conn, nil
	}
}

// validateURL performs initial URL validation and SSRF protection
func validateURL(targetURL string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("URL must use http or https scheme")
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return nil, fmt.Errorf("invalid hostname")
	}

	// Check if hostname is an IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private/reserved IP addresses is not allowed")
		}
	}

	// Block known dangerous hostnames
	lowerHostname := strings.ToLower(hostname)
	blockedHosts := []string{"localhost", "127.0.0.1", "::1", "0.0.0.0", "169.254.169.254"}
	for _, blocked := range blockedHosts {
		if lowerHostname == blocked {
			return nil, fmt.Errorf("access to this host is not allowed")
		}
	}

	// Block internal DNS suffixes (common in cloud environments)
	if strings.HasSuffix(lowerHostname, ".internal") ||
		strings.HasSuffix(lowerHostname, ".local") ||
		strings.HasSuffix(lowerHostname, ".localhost") {
		return nil, fmt.Errorf("access to internal hosts is not allowed")
	}

	return parsedURL, nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL with SSRF protection
	parsedURL, err := validateURL(targetURL)
	if err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Create client with safe dialer for SSRF protection
	client := &fasthttp.Client{
		Dial:                safeDial(5 * time.Second),
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Check content type to ensure response is HTML
	contentType := string(res.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL must return HTML content", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Limit response body size to prevent memory exhaustion
	if len(bodyBytes) > maxResponseBodySize {
		bodyBytes = bodyBytes[:maxResponseBodySize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	return "dummy title", "dummy description", nil
}

