// isBlockedHost checks if the hostname should be blocked based on known
// internal/metadata hostnames.
func isBlockedHost(hostname string) bool {
	// Block common internal/metadata hostnames that could be exploited
	blockedHosts := []string{
		"localhost",
		"localhost.localdomain",
		"ip6-localhost",
		"ip6-loopback",
		"metadata.google.internal", // GCP metadata
		"metadata",                 // Generic metadata
		"kubernetes.default",       // Kubernetes internal
		"kubernetes.default.svc",   // Kubernetes internal
	}

	lowerHost := strings.ToLower(hostname)
	for _, blocked := range blockedHosts {
		if lowerHost == blocked || strings.HasSuffix(lowerHost, "."+blocked) {
