package main

import (
	"encoding/json"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type URLRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "URL is required"})
		return
	}

	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	fastReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(fastReq)
	fastReq.SetRequestURI(req.URL)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	err := client.DoRedirects(fastReq, resp, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{URL: req.URL, Error: err.Error()})
		return
	}

	body := resp.Body()
	title, description := extractMeta(body)

	response := URLPreviewResponse{
		URL:         req.URL,
		Title:       title,
		Description: description,
	}
	json.NewEncoder(ctx).Encode(response)
}

func extractMeta(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			} else if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

