package main

import (
	"encoding/json"
	"fmt"
	"log"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// RequestPayload defines the structure for the incoming JSON request
type RequestPayload struct {
	URL string `json:"url"`
}

// PreviewResponse defines the structure for the JSON response
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the URL preview fetching logic
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse the request body
	var reqPayload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &reqPayload); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON format"})
		return
	}

	if reqPayload.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL parameter is missing"})
		return
	}

	// Initialize fasthttp client with DialDualStack as required
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Prepare the request and response objects
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqPayload.URL)

	// Perform the request using DoRedirects as required
	// MaxRedirects set to 10
	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
		return
	}

	// Extract title and description from the response body
	title, description := extractHTMLMeta(resp.Body())

	// Send the JSON response
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractHTMLMeta parses HTML content to find title and meta description
func extractHTMLMeta(body []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			} else if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	log.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

