			}
			if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func sendJSONResponse(ctx *fasthttp.RequestCtx, resp Response) {
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(resp)
}

