package main

import (
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type Request struct {
	URL string `json:"url"`
}

type Response struct {
	URL         string `json:"url"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial:         fasthttp.DialDualStack,
	ReadTimeout:  10 * time.Second,
	WriteTimeout: 10 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if string(ctx.Method()) != "POST" {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Fetch the URL
	fastReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(fastReq)
	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod("GET")

	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(fastResp)

	// Use DoRedirects to follow redirects
	err := client.DoRedirects(fastReq, fastResp, 10) // max 10 redirects
	if err != nil {
		jsonResponse(ctx, Response{
			URL:   req.URL,
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		}, fasthttp.StatusOK)
		return
	}

	// Parse HTML to extract title and meta description
	body := fastResp.Body()
	title, description := extractMetaInfo(body)

	// Return JSON response
	jsonResponse(ctx, Response{
		URL:         req.URL,
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	}, fasthttp.StatusOK)
}

func extractMetaInfo(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				title = extractText(n)
			} else if n.Data == "meta" {
				name := ""
				content := ""
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func extractText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += extractText(c)
	}
	return result
}

func jsonResponse(ctx *fasthttp.RequestCtx, data interface{}, statusCode int) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	jsonData, _ := json.Marshal(data)
	ctx.Write(jsonData)
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

